import { index, jsonb, pgTable, text, timestamp, uuid } from "drizzle-orm/pg-core";

export const accountModes = pgTable(
  "account_modes",
  {
    id: uuid("id").primaryKey().defaultRandom(),
    accountId: text("account_id").notNull(),
    mode: text("mode").notNull().default("personal"),
    status: text("status").notNull().default("active"),
    metadata: jsonb("metadata").$type<Record<string, unknown>>().notNull().default({}),
    createdAt: timestamp("created_at", { withTimezone: true }).defaultNow().notNull(),
    updatedAt: timestamp("updated_at", { withTimezone: true }).defaultNow().notNull(),
  },
  (item) => [index("account_modes_account_idx").on(item.accountId)]
);

export const accountModeValues = ["personal", "team", "hybrid"] as const;

export type AccountMode = (typeof accountModeValues)[number];

export type AccountModeConfig = {
  accountId: string;
  mode: AccountMode;
  enabled?: boolean;
  metadata?: Record<string, unknown>;
};

export function createAccountModeConfig(config: AccountModeConfig) {
  return {
    accountId: config.accountId,
    mode: config.mode,
    enabled: config.enabled ?? true,
    metadata: config.metadata ?? {},
  };
}

export function supportsOrganizations(mode: AccountMode) {
  return mode === "team" || mode === "hybrid";
}

export function supportsPersonalWorkspace(mode: AccountMode) {
  return mode === "personal" || mode === "hybrid";
}

const checklist = [
  "Choose personal, team, or hybrid defaults",
  "Document billing and invite assumptions",
  "Keep provider adapters outside the shared module",
];

export default function AccountModesPage() {
  return (
    <main className="flex flex-col gap-6 p-6">
      <div>
        <h1 className="text-2xl font-semibold">Account Modes</h1>
        <p className="text-muted-foreground">
          Configure personal, team, and hybrid account behavior for SaaS apps.
        </p>
      </div>
      <div className="grid gap-3">
        {checklist.map((item) => (
          <div key={item} className="rounded-lg border p-4 text-sm">
            {item}
          </div>
        ))}
      </div>
    </main>
  );
}
